let totalReqs = requests
| where timestamp {TimeRange}
| summarize Value = toreal(count())
| extend Name = 'Total Requests', Order = 1;
let failPct = requests
| where timestamp {TimeRange}
| summarize Total = toreal(count()), Failed = toreal(countif(success == false))
| extend Value = iff(Total > 0, round(Failed / Total * 100, 2), 0.0), Name = 'Failed %', Order = 2;
let p95Lat = requests
| where timestamp {TimeRange}
| summarize Value = coalesce(round(percentile(duration, 95), 0), 0.0)
| extend Name = 'P95 Latency (ms)', Order = 3;
let depFailPct = dependencies
| where timestamp {TimeRange}
| summarize Total = toreal(count()), Failed = toreal(countif(success == false))
| extend Value = iff(Total > 0, round(Failed / Total * 100, 2), 0.0), Name = 'Dep Failed %', Order = 4;
let depP95 = dependencies
| where timestamp {TimeRange}
| summarize Value = coalesce(round(percentile(duration, 95), 0), 0.0)
| extend Name = 'Dep P95 (ms)', Order = 5;
union totalReqs, failPct, p95Lat, depFailPct, depP95
| order by Order asc
| project Name, Value

let opIds = requests
| where timestamp {TimeRange}
| where '*' == '{OperationName}' or name == '{OperationName}'
| distinct operation_Id;
exceptions
| where timestamp {TimeRange}
| where operation_Id in (opIds)
| project timestamp, type, outerMessage, cloud_RoleName, operation_Id, problemId
| order by timestamp desc
| take 50

let sloTarget = 99.9;
let budget = 100.0 - sloTarget;
requests
| where timestamp {TimeRange}
| summarize Total = count(), Failed = countif(success == false)
| extend ErrorRate = round(toreal(Failed) / toreal(Total) * 100, 4)
| extend BudgetUsedPct = round(ErrorRate / budget * 100, 2)
| extend BudgetRemaining = round(100.0 - BudgetUsedPct, 2)
| extend Status = iff(BudgetUsedPct <= 50, 'Healthy', iff(BudgetUsedPct <= 80, 'Caution', 'Critical'))
| project SloTarget = strcat(sloTarget, '%'), ErrorBudget = strcat(budget, '%'), ActualErrorRate = strcat(ErrorRate, '%'), BudgetUsed = strcat(BudgetUsedPct, '%'), BudgetRemaining = strcat(BudgetRemaining, '%'), Status
